// LOCALVOLTS
try {
    const dataIn = msg.payload;

    let currentBuyPrice = null;
    let currentSellPrice = null;
    let currentStartTime = null;
    let currentEndTime = null;
    let demandInterval = null;
    let forecastIntervals = [];
    let hasExpectedData = false;

    for (const property in dataIn) {
        let dataItem = dataIn[property];

        let endTime = new Date(dataItem.intervalEnd);
        let startTime = new Date(endTime);
        startTime.setMinutes(endTime.getMinutes() - dataItem.intervalDuration);

        let buyPrice = normaliseValue(dataItem, "costsFlexUp");
        let sellPrice = normaliseValue(dataItem, "earningsFlexUp");

        if (dataItem.quality === "Exp") {
            hasExpectedData = true;
            currentBuyPrice = buyPrice;
            currentSellPrice = sellPrice;
            currentStartTime = startTime.toISOString();
            currentEndTime = endTime.toISOString();
            demandInterval = dataItem.demandInterval;
        }

        if (dataItem.quality === "Fcst") {
            forecastIntervals.push({
                CurrentBuyPrice: buyPrice,
                CurrentSellPrice: sellPrice,
                StartTime: startTime.toISOString(),
                EndTime: endTime.toISOString()
            });
        }
    }

    if (!hasExpectedData) {
        msg.payload = {
            error: "No Expected (Exp) data found in LocalVolts data",
            forecast_count: forecastIntervals.length,
            timestamp: new Date().toISOString()
        };
        node.log("No Expected (Exp) data found - routing to alternative output");
        return [null, msg];
    }

    msg.buyprice = currentBuyPrice;
    msg.sellprice = currentSellPrice;
    msg.starttime = currentStartTime;
    msg.endtime = currentEndTime;
    msg.forecast = forecastIntervals;
    if(demandInterval == 1) {demandInterval = true;}
    else {demandInterval = false;}
    msg.demandInterval = demandInterval;

    if (currentEndTime) {
        flow.set("lastIntervalMillis", new Date(currentEndTime).getTime());
    }

    msg.topic = "homeassistant/sensor/nodered_forecast/state";
    msg.payload = JSON.stringify({
        state: currentBuyPrice || 0,
        attributes: {
            forecast: forecastIntervals,
            current_buy_price: currentBuyPrice,
            current_sell_price: currentSellPrice,
            start_time: currentStartTime,
            end_time: currentEndTime,
            demandInterval: demandInterval,
            last_updated: new Date().toISOString(),
            forecast_count: forecastIntervals.length
        }
    });

    return [msg, null];

} catch (error) {
    const errorMsg = {
        buyprice: null,
        sellprice: null,
        starttime: null,
        endtime: null,
        demandInterval: null,
        forecast: [],
        payload: {
            error: `Error processing Localvolts data: ${error.message}`,
            timestamp: new Date().toISOString()
        }
    };

    node.error(`Error processing Localvolts data: ${error.message}`, msg);
    return [null, errorMsg];
}

function normaliseValue(item, property) {
    let adjustedVal = item[property];

    if (
        property == "earningsFlexUp" && item.earningsFlexUnits == "c/kWh" ||
        property == "costsFlexUp" && item.costsFlexUnits == "c/kWh"
    ) { adjustedVal = item[property] / 100; }

    else if (property == "quality") {
        if (item[property] == "Act")        adjustedVal = "Actual"
        else if (item[property] == "Exp")   adjustedVal = "Expected"
        else if (item[property] == "Fcst")  adjustedVal = "Forecast"
    }

    return adjustedVal;
}

if (msg.provider == "LocalVolts") {
    return [msg,null,null];
}
else if (msg.provider == "Amber Electric") {
    return [null,msg,null];
}
else if (msg.provider == "Flow Power") {
    return[null,null,msg];
}

// AMBER ELECTRIC
try {
    const dataIn = msg.payload;

    let currentBuyPrice = null;
    let currentSellPrice = null;
    let currentStartTime = null;
    let currentEndTime = null;
    let demandInterval = null;
    let forecastIntervals = [];

    let hasCurrentGeneralFinal = false;
    let sawCurrentGeneralEstimate = false;

    for (const dataItem of dataIn) {
        const startTimeIso = new Date(dataItem.startTime).toISOString();
        const endTimeIso   = new Date(dataItem.endTime).toISOString();

        const perKwhCents = Number(dataItem.perKwh);
        const buyDollars  = perKwhCents / 100;
        const sellDollars = (perKwhCents / 100) * -1;

        if (dataItem.type === "CurrentInterval") {
            if (dataItem.channelType === "general") {
                if (dataItem.estimate === false) {
                    hasCurrentGeneralFinal = true;
                    currentBuyPrice = buyDollars;
                    currentStartTime = startTimeIso;
                    currentEndTime = endTimeIso;
                    demandInterval = dataItem.tariffInformation?.demandWindow || false;
                } else {
                    sawCurrentGeneralEstimate = true;
                }
            }

            if (dataItem.channelType === "feedIn") {
                if (dataItem.estimate === false) {
                    currentSellPrice = sellDollars;
                }
            }
        }

        if (dataItem.type === "ForecastInterval") {
            let existing = forecastIntervals.find(iv =>
                iv.StartTime === startTimeIso && iv.EndTime === endTimeIso
            );
            if (!existing) {
                existing = {
                    CurrentBuyPrice: null,
                    CurrentSellPrice: null,
                    StartTime: startTimeIso,
                    EndTime: endTimeIso
                };
                forecastIntervals.push(existing);
            }

            if (dataItem.channelType === "general") {
                existing.CurrentBuyPrice = buyDollars;
            }
            if (dataItem.channelType === "feedIn") {
                existing.CurrentSellPrice = sellDollars;
            }
        }
    }

    if (!hasCurrentGeneralFinal) {
        const reason = sawCurrentGeneralEstimate
            ? "CurrentInterval general exists but is an estimate (true)"
            : "No CurrentInterval general found";
        const err = {
            error: `Aborting publish: ${reason}`,
            forecast_count: forecastIntervals.length,
            timestamp: new Date().toISOString()
        };
        node.log(err.error);
        return [null, { payload: err }];
    }

    forecastIntervals.sort((a, b) =>
        new Date(a.StartTime).getTime() - new Date(b.StartTime).getTime()
    );

    demandInterval = (demandInterval == 1) ? true : Boolean(demandInterval);

    msg.buyprice = currentBuyPrice;
    msg.sellprice = currentSellPrice;
    msg.starttime = currentStartTime;
    msg.endtime = currentEndTime;
    msg.forecast = forecastIntervals;
    msg.demandInterval = demandInterval;

    if (currentEndTime) {
        flow.set("lastIntervalMillis", new Date(currentEndTime).getTime());
    }

    msg.topic = "homeassistant/sensor/nodered_forecast/state";
    msg.payload = JSON.stringify({
        state: currentBuyPrice || 0,
        attributes: {
            forecast: forecastIntervals,
            current_buy_price: currentBuyPrice,
            current_sell_price: currentSellPrice,
            start_time: currentStartTime,
            end_time: currentEndTime,
            demandInterval: demandInterval,
            last_updated: new Date().toISOString(),
            forecast_count: forecastIntervals.length
        }
    });

    return [msg, null];

} catch (error) {
    const errorMsg = {
        buyprice: null,
        sellprice: null,
        starttime: null,
        endtime: null,
        demandInterval: null,
        forecast: [],
        payload: {
            error: `Error processing Amber Electric data: ${error.message}`,
            timestamp: new Date().toISOString()
        }
    };
    node.error(`Error processing Amber Electric data: ${error.message}`, msg);
    return [null, errorMsg];
}

let now = new Date();
let timestamp = now.getHours().toString().padStart(2, '0') + ":" + now.getMinutes().toString().padStart(2, '0');
let datestamp = now.getFullYear() + "-" + (now.getMonth() + 1).toString().padStart(2, '0') + "-" + now.getDate().toString().padStart(2, '0');
let datemonthstamp = now.getFullYear() + "-" + (now.getMonth() + 1).toString().padStart(2, '0');

msg.filename = "/config/node-red/" + msg.provider + "/" + datemonthstamp + "/" + datestamp +".csv";
msg.payload = datestamp + " " + timestamp + "," + msg.buyprice + "," + msg.sellprice;
return msg;

let now = new Date();
let timestamp = now.getHours().toString().padStart(2, '0') + ":" + now.getMinutes().toString().padStart(2, '0');
let datestamp = now.getFullYear() + "-" + (now.getMonth() + 1).toString().padStart(2, '0')  + "-" + now.getDate().toString().padStart(2, '0');
let datemonthstamp = now.getFullYear() + "-" + (now.getMonth() + 1).toString().padStart(2, '0');

msg.filename = "/config/node-red/" + msg.provider + "/" + datemonthstamp + ".csv";
msg.payload = datestamp + " " + timestamp + "," + msg.buyprice + "," + msg.sellprice;
return msg;

let failureCount            = flow.get("apiFailureCount") || 0;
let systemInFailureMode     = flow.get("systemInFailureMode") || false;

let noPrimaryDataStreak     = flow.get("noPrimaryDataStreak") || 0;
const NO_PRIMARY_LIMIT      = 25;

const isArray = (v) => Array.isArray(v);
const hasProp = (o, k) => o && Object.prototype.hasOwnProperty.call(o, k);

function isCompleteArrayPayload(payload) {
  return isArray(payload) && payload.length > 0;
}

function hasLocalVoltsPrimary(payload) {
  try {
    return payload.some(it => it && it.quality === "Exp");
  } catch { return false; }
}

function hasAmberPrimary(payload) {
  try {
    return payload.some(it =>
      it &&
      it.type === "CurrentInterval" &&
      it.channelType === "general" &&
      it.estimate === false
    );
  } catch { return false; }
}

function detectPrimaryDatapoint(payload) {
  if (!isCompleteArrayPayload(payload)) return { isComplete: false, hasPrimary: false, vendor: "unknown" };

  const looksLocalVolts = payload.some(it => it && typeof it === "object" && "quality" in it);
  if (looksLocalVolts) {
    return { isComplete: true, hasPrimary: hasLocalVoltsPrimary(payload), vendor: "localvolts" };
  }

  const looksAmber = payload.some(it => it && typeof it === "object" && "type" in it);
  if (looksAmber) {
    return { isComplete: true, hasPrimary: hasAmberPrimary(payload), vendor: "amber" };
  }

  const isValidResponse = payload.some(item =>
    hasProp(item, "NMI") || (item.type && item.type === "ActualInterval")
  );

  return { isComplete: isValidResponse, hasPrimary: false, vendor: "unknown" };
}

const payload = msg.payload;
const { isComplete, hasPrimary, vendor } = isCompleteArrayPayload(payload)
  ? detectPrimaryDatapoint(payload)
  : { isComplete: false, hasPrimary: false, vendor: "unknown" };

let isValidResponse = false;
if (isArray(payload) && payload.length > 0) {
  isValidResponse = payload.some(item =>
    hasProp(item, 'NMI') || (item.type && item.type === 'ActualInterval') || (item?.type === 'CurrentInterval')
  );
}

if (isComplete) {
  if (hasPrimary) {
    if (noPrimaryDataStreak > 0) {
      node.log(`[health] ${vendor}: primary datapoint found, resetting noPrimaryDataStreak (${noPrimaryDataStreak} → 0)`);
    }
    noPrimaryDataStreak = 0;
    flow.set("noPrimaryDataStreak", 0);

    flow.set("apiFailureCount", 0);

    if (systemInFailureMode) {
      flow.set("systemInFailureMode", false);
      msg.topic = "recover";
      msg.vendor = vendor;
      msg.reason = "Primary datapoint observed (recovered)";
      node.status({ fill: "green", shape: "dot", text: "API recovered - turning system back on" });
      return [null, msg];
    } else {
      node.status({ fill: "green", shape: "dot", text: "API working normally" });
      return [null, null];
    }

  } else {
    noPrimaryDataStreak += 1;
    flow.set("noPrimaryDataStreak", noPrimaryDataStreak);

    node.status({
      fill: "yellow",
      shape: "ring",
      text: `No primary data (${vendor}) ${noPrimaryDataStreak}/${NO_PRIMARY_LIMIT}`
    });

    if (noPrimaryDataStreak >= NO_PRIMARY_LIMIT && !systemInFailureMode) {
      flow.set("systemInFailureMode", true);
      msg.topic = "failure";
      msg.vendor = vendor;
      msg.reason = `No primary datapoint for ${NO_PRIMARY_LIMIT} consecutive messages`;
      node.status({ fill: "red", shape: "dot", text: `API DOWN: no primary data x${NO_PRIMARY_LIMIT}` });
      return [msg, null]; // output 1
    }

    return [null, null];
  }
}

if (isValidResponse) {
  flow.set("apiFailureCount", 0);

  if (systemInFailureMode) {
    flow.set("systemInFailureMode", false);
    msg.topic = "recover";
    msg.vendor = "unknown";
    msg.reason = "Legacy validity path recovered";
    node.status({ fill: "green", shape: "dot", text: "API recovered - turning system back on" });
    return [null, msg];
  } else {
    node.status({ fill: "green", shape: "dot", text: "API working normally" });
    return [null, null];
  }

} else {
  failureCount++;
  flow.set("apiFailureCount", failureCount);

  node.status({ fill: "yellow", shape: "ring", text: `API failed ${failureCount}/5 times` });

  if (failureCount >= 5 && !systemInFailureMode) {
    flow.set("systemInFailureMode", true);
    msg.topic = "failure";
    msg.vendor = "unknown";
    msg.reason = "Legacy validity path: 5 consecutive failures";
    node.status({ fill: "red", shape: "dot", text: "API failed 5 times - entering failure mode" });
    return [msg, null];
  }

  return [null, null];
}

msg.payload = msg.provider + " API appears to be down or internet connectivty lost! Energy Manager has set inverter to self-consumption until the API returns to normal.";
msg.headers = {};
msg.headers['tag'] = 'x';
msg.headers['X-Title'] = 'Energy Manager';

return msg;

msg.payload = msg.provider + " API is back online again, or internet connectivity restored. Energy Manager will be re-enabled.";
msg.headers = {};
msg.headers['tag'] = 'white_check_mark';
msg.headers['X-Title'] = 'Energy Manager';

return msg;

var amberKeyLength = msg.amber_key ? msg.amber_key.length : 0;

if (amberKeyLength > 10) {
    return [msg, null];
} else {
    return [null, msg];
}

var lvKeyLength = msg.lv_key ? msg.lv_key.length : 0;

if (lvKeyLength > 10) {
    return [msg, null];
} else {
    return [null, msg];
}

msg.payload = {
    action: "persistent_notification.create",
    data: {
        message: "<font color=orange><strong>Warning: " + msg.provider + " API Failure</strong></font><br><br>Connection to " + msg.provider + " API has failed and Energy Manager has been put into self-consumption mode.<br><br>Energy Manager will keep checking and enable again once the API has been reached successfully.",
        title: "⚠️ Energy Manager Warning!"
    }
};

return msg;

msg.payload = {
    action: "persistent_notification.create",
    data: {
        message: "<font color=green><strong>Notice: The " + msg.provider + " API has returned.</strong></font><br><br>Connection to " + msg.provider + "'s API has succeeded again and Energy Manager control has been re-enabled.",
        title: "✅ Energy Manager Notification"
    }
};

return msg;

if (msg.emergency_override === true) {
    return [null, msg];
} else {
    return [msg, null];
}

let now = new Date();

let startDate = now.toISOString().split("T")[0];

let tomorrow = new Date(now);
tomorrow.setDate(now.getDate() + 2);
let endDate = tomorrow.toISOString().split("T")[0];

let site = msg.amber_site;
msg.url = `https://api.amber.com.au/v1/sites/${site}/prices?startDate=${startDate}&endDate=${endDate}&resolution=5`;

return msg;

msg.precision = 'ms';

function asObj(x) {
  if (typeof x === "string") {
    try { return JSON.parse(x); } catch { return null; }
  }
  if (x && typeof x === "object") return x;
  return null;
}

function firstDefined(...vals) {
  for (const v of vals) if (v !== undefined && v !== null) return v;
  return undefined;
}

const root = asObj(msg.payload) || asObj(msg.data) || {};
const entity =
  firstDefined(
    root.new_state,
    root,
  ) || {};

const attrs =
  firstDefined(
    entity.attributes,
    root.attributes,
    (entity.data && entity.data.attributes)
  ) || {};

const items = firstDefined(
  Array.isArray(attrs.forecast) ? attrs.forecast : undefined,
  Array.isArray(attrs.Forecast) ? attrs.Forecast : undefined
);

if (!items || !items.length) {
  const keys = Object.keys(attrs || {});
  node.warn({
    msg: "No forecast[] found",
    tried_paths: [
      "payload.attributes.forecast",
      "payload.attributes.Forecast",
      "data.attributes.forecast",
      "data.attributes.Forecast",
      "new_state.attributes.forecast",
      "new_state.attributes.Forecast",
    ],
    available_attribute_keys: keys.slice(0, 25)
  });
  node.status({ fill: "red", shape: "dot", text: "No forecast[]" });
  return null;
} else {
  node.status({ fill: "blue", shape: "dot", text: `forecast[${items.length}]` });
}

const entId = firstDefined(entity.entity_id, root.entity_id, "sensor.nodered_forecast");
const site = firstDefined(msg.site_id, msg.site, null);

const rows = [];
for (const it of items) {
  const importPrice = Number(it.CurrentBuyPrice);
  const fitPrice = Number(it.CurrentSellPrice);

  if (!Number.isFinite(importPrice) && !Number.isFinite(fitPrice)) continue;

  const startMs = Date.parse(it.StartTime);
  const endMs = Date.parse(it.EndTime);
  if (!Number.isFinite(startMs) || !Number.isFinite(endMs)) continue;

  const alignedStartMs = Math.floor(startMs / 300000) * 300000;

  const row = {
    measurement: "forecast_prices",
    tags: {
      source: "ha",
      entity_id: String(entId)
    },
    fields: {},
    timestamp: alignedStartMs
  };
  if (site != null) row.tags.site_id = String(site);
  if (Number.isFinite(importPrice)) row.fields.import = importPrice;
  if (Number.isFinite(fitPrice)) row.fields.fit = fitPrice;

  rows.push(row);
}

const misaligned = rows.filter(r => (r.timestamp % 300000) !== 0).length;
if (misaligned) node.warn(`forecast_prices: ${misaligned}/${rows.length} timestamps NOT on 5-min grid`);

msg.payload = rows;
node.status({ fill: "green", shape: "dot", text: `wrote ${rows.length} pts` });
return msg;

// FLOW POWER
try {
    const data = msg.payload || {};

    if (data.ready !== true) {
        return [null, {
            payload: {
                error: "Flow Power interval.json not ready (ready != true)",
                ready: data.ready,
                timestamp: new Date().toISOString()
            }
        }];
    }

    const startStr = data.dispatch_interval_start_utc;
    const endStr   = data.dispatch_interval_end_utc;

    if (!startStr || !endStr) {
        return [null, {
            payload: {
                error: "Flow Power interval.json missing dispatch_interval_start_utc or dispatch_interval_end_utc",
                dispatch_interval_start_utc: startStr || null,
                dispatch_interval_end_utc: endStr || null,
                timestamp: new Date().toISOString()
            }
        }];
    }

    const startMs = Date.parse(startStr);
    const endMs   = Date.parse(endStr);

    if (!Number.isFinite(startMs) || !Number.isFinite(endMs)) {
        return [null, {
            payload: {
                error: "Flow Power interval.json has invalid ISO timestamps",
                dispatch_interval_start_utc: startStr,
                dispatch_interval_end_utc: endStr,
                timestamp: new Date().toISOString()
            }
        }];
    }

    const nowMs = Date.now();

    if (!(nowMs >= startMs && nowMs < endMs)) {
        return [null, {
            payload: {
                error: "Flow Power data not in current dispatch interval (now not within start/end)",
                now_utc: new Date(nowMs).toISOString(),
                dispatch_interval_start_utc: new Date(startMs).toISOString(),
                dispatch_interval_end_utc: new Date(endMs).toISOString(),
                timestamp: new Date().toISOString()
            }
        }];
    }

    msg.starttime = new Date(startMs).toISOString();
    msg.endtime   = new Date(endMs).toISOString();

    flow.set("lastIntervalMillis", endMs);

    return [msg, null];

} catch (error) {
    node.error(`Error processing Flow Power interval.json: ${error.message}`, msg);
    return [null, {
        payload: {
            error: `Error processing Flow Power interval.json: ${error.message}`,
            timestamp: new Date().toISOString()
        }
    }];
}

if (msg.emergency_override === true) {
    return [null, msg];
} else {
    return [msg, null];
}

let today = new Date();
let current_hour = today.getHours();
let current_minute = today.getMinutes();

const safeGet = (value, defaultValue = null) => {
    return (value !== undefined && value !== null) ? value : defaultValue;
};

const safeGetNumber = (value, defaultValue = 0) => {
    if (value === null || value === undefined || value === "") return defaultValue;
    const num = parseFloat(value);
    return (!isNaN(num) && isFinite(num)) ? num : defaultValue;
};

const safeGetBoolean = (value, defaultValue = false) => {
    if (typeof value === 'boolean') return value;
    if (typeof value === 'string') return value.toLowerCase() === 'true';
    if (typeof value === 'number') return value !== 0;
    return defaultValue;
};

const safeGetString = (value, defaultValue = "") => {
    if (value === null || value === undefined) return defaultValue;
    return String(value);
};

const safeGetEntity = (entity, defaultValue = {}) => {
    if (entity && typeof entity === 'object') return entity;
    return defaultValue;
};

const isValidSolarData = (data) => {
    return data !== null && data !== undefined && data !== "null" && data !== "unknown";
};

try {
    msg.headers = {
        "Content-Type": "application/json"
    };

    let solarForecasts = [];
    try {
        if (global.homeassistant &&
            global.homeassistant.homeAssistant &&
            global.homeassistant.homeAssistant.states) {

            const solarForecastEntity = global.homeassistant.homeAssistant.states['sensor.solar_pv_forecast_1'];
            if (solarForecastEntity &&
                solarForecastEntity.attributes &&
                Array.isArray(solarForecastEntity.attributes.forecasts)) {
                solarForecasts = solarForecastEntity.attributes.forecasts;
            }
        }
    } catch (solarError) {
        node.warn("Solar forecast data unavailable: " + solarError.message);
    }


    msg.payload = {
        apiKey: safeGetString(msg.em_key),
        em_api_version: safeGetString(msg.em_api_version),
        em_version: safeGetString(msg.em_version),
        timezone: safeGetString(msg.timezone, "AEST"),
        current_hour: current_hour,
        current_minute: current_minute,
        inverter_brand: safeGetString(msg.inverter_brand),
        inverter_serial_number: safeGetString(msg.serial_number),
        inverter_export_limit: safeGetNumber(msg.inverter_export_limit),
        curtailing_enabled: safeGetBoolean(msg.curtailing_enabled),

        // Financial data (FIT and buy prices)
        fit: safeGetNumber(msg.fit),
        buy: safeGetNumber(msg.buy),

        // Battery data
        battery: safeGetNumber(msg.battery_level),
        battery_capacity: safeGetNumber(msg.battery_capacity),
        min_soc: safeGetNumber(msg.min_soc),
        max_soc: safeGetNumber(msg.max_soc),
        battery_charge_limit: safeGetNumber(msg.battery_charge_limit),
        battery_discharge_limit: safeGetNumber(msg.battery_discharge_limit),

        // Power data
        dc_power_now: safeGetNumber(msg.dc_power_now),
        electricity_provider: safeGetString(msg.electricity_provider, "LocalVolts"),
        electricity_distributor: safeGetString(msg.electricity_distributor, "Not Configured"),
        electricity_distributor_demand_enabled: safeGetBoolean(msg.electricity_distributor_demand_enabled, true),
        solar_array_size: safeGetNumber(msg.solar_array_size),
        load_now: safeGetNumber(msg.load_now),

        // Generation and usage
        daily_generation: safeGetNumber(msg.daily_generation),
        charge: safeGetNumber(msg.charge),
        discharge: safeGetNumber(msg.discharge),

        // Daily/Monthly totals
        daily_buy: safeGetNumber(msg.daily_buy),
        daily_sell: safeGetNumber(msg.daily_sell),
        monthly_buy: safeGetNumber(msg.monthly_buy),
        monthly_sell: safeGetNumber(msg.monthly_sell),

        // Weather data
        rain_today: safeGetNumber(msg.rain_today),
        rain_tomorrow: safeGetNumber(msg.rain_tomorrow),
        rain_tomorrow_definition: safeGetNumber(msg.rain_tomorrow_definition),
        rain_today_definition: safeGetNumber(msg.rain_today_definition),
        weather_state: safeGetString(msg.weather_state, "clear"),

        // Forecast data
        forecast: (() => {
            let forecastArray = [];

            if (msg.forecast_obj &&
                msg.forecast_obj.attributes &&
                Array.isArray(msg.forecast_obj.attributes.forecast)) {
                forecastArray = msg.forecast_obj.attributes.forecast;
            } else if (Array.isArray(msg.forecast)) {
