try {
    if (!historyData || !emVersion) {
        flow.set("emVersionOk", true);
        return [msg, null];
    }

    if (typeof historyData === 'string') {
        historyData = historyData.trim();

        if (!historyData) {
            flow.set("emVersionOk", true);
            return [msg, null];
        }

        historyData = historyData.split('\n');
    }

    if (!Array.isArray(historyData) || historyData.length < 2) {
        flow.set("emVersionOk", true);
        return [msg, null];
    }

    if (typeof emVersion !== 'string') {
        flow.set("emVersionOk", true);
        return [msg, null];
    }

    const countBackRaw = historyData[0];
    const countBack = Number(countBackRaw);

    if (isNaN(countBack)) {
        flow.set("emVersionOk", true);
        return [msg, null];
    }

    const history = historyData.slice(1);

    if (history.length === 0) {
        flow.set("emVersionOk", true);
        return [msg, null];
    }

    const versionIndex = history.indexOf(emVersion);

    if (versionIndex === -1) {
        flow.set("emVersionOk", true);
        return [msg, null];
    }

    const totalHistoryLength = history.length;
    const versionsAgo = (totalHistoryLength - 1) - versionIndex;

    if (versionsAgo > countBack) {

        flow.set("emVersionOk", false);

        msg.payload = {
            action: "persistent_notification.create",
            data: {
                message: "<font color=blue><strong>Your current version of Energy Manager is outdated and communication with the API servers has been restricted.</strong></font><br><br>Please go to the EM updates page and update to the latest. Once done, Energy Manager will start communicating with the servers once again.",
