            }
        };

        return [null, msg];
    } else if (versionsAgo === countBack) {

        flow.set("emVersionOk", true);

        msg.payload = {
            action: "persistent_notification.create",
            data: {
                message: "<font color=orange><strong>Warning: Your Energy Manager version is getting outdated.</strong></font><br><br>You are currently using a version that is one update away from having API access restricted. Please update to the latest version soon to ensure uninterrupted service.",
                title: "🛠️ Energy Manager Warning!"
            }
        };

        return [null, msg];
    } else {
        flow.set("emVersionOk", true);
        return [msg, null];
    }

} catch (error) {
