if (Buffer.isBuffer(src)) fileText = src.toString("utf8");
else if (typeof src === "string") fileText = src;
else fileText = "";

const ha = global.get("homeassistant");
const states =
    ha?.states ||
    ha?.homeAssistant?.states ||
    ha?.homeAssistant?.homeAssistant?.states ||
    {};

const matches = (fileText || "").match(/sensor\.[a-zA-Z0-9_]+/g) || [];
const entities = [...new Set(matches)];

let auxTotal = 0;
const auxDetails = [];

for (const entityId of entities) {
    const s = states[entityId];
    if (!s) {
        auxDetails.push({ entityId, ok: false, reason: "not_found" });
        continue;
    }

    const v = Number(s.state);
    if (isFinite(v)) {
        auxTotal += v;
        auxDetails.push({ entityId, ok: true, w: v });
    } else {
        auxDetails.push({ entityId, ok: false, reason: `non_numeric:${s.state}` });
    }
}

